import React, { useEffect, useState, useCallback, useRef } from 'react';
import { useDispatch, useSelector } from 'react-redux';
import { setWeather, setForecast, setLoading, setError } from '../redux/slices/weatherSlice';
import { weatherApi, locationApi, getUserLocation } from '../services/api';
import SearchBar from '../components/SearchBar';
import CurrentWeather from '../components/CurrentWeather';
import Forecast from '../components/Forecast';
import WeatherChart from '../components/WeatherChart';
import SavedLocations from '../components/SavedLocations';
import LiveClock from '../components/LiveClock';
import { MapPin, BookmarkPlus, AlertCircle, RefreshCw, Loader2, RotateCcw } from 'lucide-react';
import useWeatherTheme from '../hooks/useWeatherTheme';

const AUTO_REFRESH_MS = 5 * 60 * 1000; // 5 minutes

const Dashboard = () => {
  const dispatch = useDispatch();
  const { current, forecast, loading, error } = useSelector((state) => state.weather);
  const { token } = useSelector((state) => state.auth);

  const [isCelsius,      setIsCelsius]      = useState(true);
  const [refreshTrigger, setRefreshTrigger] = useState(0);
  const [savingLocation, setSavingLocation] = useState(false);
  const [lastUpdated,    setLastUpdated]    = useState(null);
  const [autoRefreshing, setAutoRefreshing] = useState(false);
  const lastParamsRef = useRef(null);

  const theme = useWeatherTheme(current?.weather[0]?.main);

  /* ── fetch helper ── */
  const fetchWeatherAndForecast = useCallback(async (params) => {
    dispatch(setLoading());
    lastParamsRef.current = params;
    try {
      const [w, f] = await Promise.all([
        weatherApi.getCurrentWeather(params),
        weatherApi.getForecast(params),
      ]);
      dispatch(setWeather(w.data));
      dispatch(setForecast(f.data));
      setLastUpdated(new Date());
    } catch (e) {
      dispatch(setError(e.response?.data?.message || 'City not found. Please try another name.'));
    }
  }, [dispatch]);

  /* ── geolocation auto-detect ── */
  const handleAuto = useCallback(async () => {
    dispatch(setLoading());
    try {
      const coords = await getUserLocation();
      fetchWeatherAndForecast(coords);
    } catch {
      fetchWeatherAndForecast({ city: 'London' });
    }
  }, [dispatch, fetchWeatherAndForecast]);

  /* ── silent auto-refresh ── */
  const silentRefresh = useCallback(async () => {
    if (!lastParamsRef.current) return;
    setAutoRefreshing(true);
    try {
      const [w, f] = await Promise.all([
        weatherApi.getCurrentWeather(lastParamsRef.current),
        weatherApi.getForecast(lastParamsRef.current),
      ]);
      dispatch(setWeather(w.data));
      dispatch(setForecast(f.data));
      setLastUpdated(new Date());
    } catch { /* silent */ }
    finally { setAutoRefreshing(false); }
  }, [dispatch]);

  /* ── initial load ── */
  useEffect(() => { handleAuto(); }, [handleAuto]);

  /* ── auto-refresh timer ── */
  useEffect(() => {
    const id = setInterval(silentRefresh, AUTO_REFRESH_MS);
    return () => clearInterval(id);
  }, [silentRefresh]);

  /* ── save location ── */
  const handleSaveLocation = async () => {
    if (!current) return;
    setSavingLocation(true);
    try {
      await locationApi.saveLocation({
        cityName: current.name,
        latitude: current.coord.lat,
        longitude: current.coord.lon,
      });
      setRefreshTrigger(prev => prev + 1);
    } catch (e) { console.error('Failed to save location', e); }
    finally { setSavingLocation(false); }
  };

  /* ── last-updated label ── */
  const updatedLabel = lastUpdated
    ? lastUpdated.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
    : null;

  return (
    <div className={`min-h-screen transition-all duration-700 ${theme.background} font-sans`}>
      <div className='max-w-5xl mx-auto px-4 md:px-6 py-6 pb-20'>

        {/* ── Top bar: Search + controls ── */}
        <div className='glass-card p-4 mb-8 animate-slide-down'>
          <div className='flex flex-col md:flex-row gap-3 items-center justify-between'>

            {/* Search */}
            <div className='w-full md:flex-1'>
              <SearchBar onSearch={(city) => fetchWeatherAndForecast({ city })} theme={theme} />
            </div>

            {/* Right controls */}
            <div className='flex gap-2 items-center flex-shrink-0'>

              {/* °C / °F toggle */}
              <button
                onClick={() => setIsCelsius(!isCelsius)}
                className='flex items-center gap-1.5 px-4 py-2.5 rounded-xl font-bold text-sm transition-all duration-200 hover:scale-105 active:scale-95'
                style={{ background: 'rgba(255,255,255,0.1)', border: '1px solid rgba(255,255,255,0.15)' }}>
                <span className='text-white/60'>Unit:</span>
                <span className='text-blue-300 font-black'>{isCelsius ? '°C' : '°F'}</span>
              </button>

              {/* Geolocation */}
              <button
                onClick={handleAuto}
                title='Detect my location'
                className='p-2.5 rounded-xl transition-all duration-200 hover:scale-110 hover:rotate-12 active:scale-95'
                style={{ background: 'rgba(255,255,255,0.1)', border: '1px solid rgba(255,255,255,0.15)' }}>
                <MapPin className='text-red-400 w-5 h-5' />
              </button>

              {/* Live clock */}
              <div className='hidden lg:block pl-3'
                style={{ borderLeft: '1px solid rgba(255,255,255,0.1)' }}>
                <LiveClock />
              </div>
            </div>
          </div>

          {/* Status bar */}
          {updatedLabel && (
            <div className='flex items-center gap-3 mt-3 pt-3'
              style={{ borderTop: '1px solid rgba(255,255,255,0.06)' }}>
              <div className='flex items-center gap-1.5'>
                <span className='relative flex h-1.5 w-1.5'>
                  <span className='animate-ping-soft absolute inline-flex h-full w-full rounded-full bg-green-400' />
                  <span className='relative inline-flex rounded-full h-1.5 w-1.5 bg-green-500' />
                </span>
                <span className='text-xs text-white/40 font-medium'>Updated at {updatedLabel}</span>
              </div>
              {autoRefreshing && (
                <div className='flex items-center gap-1 text-xs text-blue-300/70'>
                  <RefreshCw size={10} className='animate-spin' />
                  <span>Refreshing…</span>
                </div>
              )}
              <span className='text-xs text-white/25 ml-auto hidden sm:block'>Auto-refresh every 5 min</span>
            </div>
          )}
        </div>

        {/* ── Content states ── */}

        {/* Loading */}
        {loading ? (
          <div className='flex flex-col items-center justify-center py-40 gap-6 animate-fade-in'>
            <div className='relative'>
              <div className='absolute inset-0 rounded-full bg-indigo-500/20 blur-xl animate-glow-pulse' />
              <div className='relative p-6 glass-card rounded-full'>
                <Loader2 className='w-12 h-12 text-indigo-400 animate-spin' />
              </div>
            </div>
            <div className='text-center'>
              <p className='text-xl font-bold text-white/80 tracking-wide'>Fetching live weather data</p>
              <p className='text-sm text-white/35 mt-1'>Connecting to weather servers…</p>
            </div>
          </div>

        /* Error */
        ) : error ? (
          <div className='max-w-sm mx-auto my-16 glass-card p-8 text-center animate-scale-up'>
            <div className='inline-flex p-4 rounded-2xl mb-4'
              style={{ background: 'rgba(239,68,68,0.15)', border: '1px solid rgba(239,68,68,0.25)' }}>
              <AlertCircle className='w-10 h-10 text-red-400' />
            </div>
            <h3 className='text-lg font-bold text-white mb-2'>Couldn't load weather</h3>
            <p className='text-red-300/80 text-sm mb-6 font-medium'>{error}</p>
            <button
              onClick={handleAuto}
              className='flex items-center gap-2 mx-auto px-6 py-2.5 rounded-xl font-bold text-sm text-white transition-all duration-200 hover:scale-105 active:scale-95'
              style={{ background: 'linear-gradient(135deg, #6366f1, #8b5cf6)' }}>
              <RotateCcw size={16} />
              Try again
            </button>
          </div>

        /* Weather data */
        ) : current ? (
          <div className='space-y-6'>

            {/* Hero: current weather + save btn */}
            <div className='relative card-enter'>
              <CurrentWeather weather={current} isCelsius={isCelsius} theme={theme} />
              {token && (
                <button
                  onClick={handleSaveLocation}
                  disabled={savingLocation}
                  title='Save this location'
                  className='absolute top-5 right-5 p-3 rounded-2xl transition-all duration-300 hover:scale-110 hover:rotate-12 active:scale-95 disabled:opacity-50'
                  style={{ background: 'rgba(255,255,255,0.1)', border: '1px solid rgba(255,255,255,0.15)' }}>
                  {savingLocation
                    ? <RefreshCw className='w-5 h-5 text-yellow-300 animate-spin' />
                    : <BookmarkPlus className='w-5 h-5 text-yellow-400' />}
                </button>
              )}
            </div>

            {/* Chart */}
            <div className='card-enter delay-200'>
              <WeatherChart forecast={forecast} isCelsius={isCelsius} theme={theme} />
            </div>

            {/* Forecast */}
            <div className='card-enter delay-300'>
              <Forecast forecast={forecast} isCelsius={isCelsius} theme={theme} />
            </div>

            {/* Saved locations */}
            {token && (
              <div className='card-enter delay-400'>
                <SavedLocations
                  onSelectLocation={(city) => fetchWeatherAndForecast({ city })}
                  refreshTrigger={refreshTrigger}
                  theme={theme}
                />
              </div>
            )}
          </div>
        ) : null}
      </div>
    </div>
  );
};

export default Dashboard;
